import React, { useEffect, useState } from 'react';
import { Table, TableBody, TableCell, TableHead, TableRow, Typography, Box, CircularProgress } from '@material-ui/core';
import { getFullReport } from '../services/ApiService';
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  root: {
    padding: theme.spacing(3),
  },
  section: {
    marginBottom: theme.spacing(4),
  },
  total: {
    marginTop: theme.spacing(2),
    fontWeight: 'bold',
  },
}));

export default function ReportManagement() {
  const classes = useStyles();
  const [report, setReport] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    setLoading(true);
    getFullReport().then(res => {
      if (res.error) {
        setError(res.error);
      } else {
        setReport(res.data);
      }
      setLoading(false);
    });
  }, []);

  if (loading) return <CircularProgress />;
  if (error) return (
    <div className={classes.root}>
      <Typography variant="h4" gutterBottom>Reports</Typography>
      <Typography color="error">{error}</Typography>
    </div>
  );

  if (!report) return <Typography>No report data available</Typography>;

  return (
    <div className={classes.root}>
      <Typography variant="h4" gutterBottom>Full Report</Typography>

      <Box className={classes.section}>
        <Typography variant="h5" gutterBottom>Purchases</Typography>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Item</TableCell>
              <TableCell>Quantity</TableCell>
              <TableCell>Cost</TableCell>
              <TableCell>Company</TableCell>
              <TableCell>Created At</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {report.purchases.map(purchase => (
              <TableRow key={purchase.id}>
                <TableCell>{purchase.item?.name || 'N/A'}</TableCell>
                <TableCell>{purchase.quantity}</TableCell>
                <TableCell>{purchase.cost}</TableCell>
                <TableCell>{purchase.company?.name || 'N/A'}</TableCell>
                <TableCell>{new Date(purchase.createdAt).toLocaleString()}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
        <Typography className={classes.total}>Total Purchase: {report.totalPurchase}</Typography>
      </Box>

      <Box className={classes.section}>
        <Typography variant="h5" gutterBottom>Sales</Typography>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Item</TableCell>
              <TableCell>Quantity</TableCell>
              <TableCell>Price</TableCell>
              <TableCell>Wholesale</TableCell>
              <TableCell>Company</TableCell>
              <TableCell>Created At</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {report.sales.map(sale => (
              <TableRow key={sale.id}>
                <TableCell>{sale.item?.name || 'N/A'}</TableCell>
                <TableCell>{sale.quantity}</TableCell>
                <TableCell>{sale.price}</TableCell>
                <TableCell>{sale.isWholesale ? 'Yes' : 'No'}</TableCell>
                <TableCell>{sale.company?.name || 'N/A'}</TableCell>
                <TableCell>{new Date(sale.createdAt).toLocaleString()}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
        <Typography className={classes.total}>Total Sale: {report.totalSale}</Typography>
      </Box>

      <Box className={classes.section}>
        <Typography variant="h5" gutterBottom>FOCs</Typography>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Item</TableCell>
              <TableCell>Quantity</TableCell>
              <TableCell>Reason</TableCell>
              <TableCell>Created At</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {report.focs.map(foc => (
              <TableRow key={foc.id}>
                <TableCell>{foc.item?.name || 'N/A'}</TableCell>
                <TableCell>{foc.quantity}</TableCell>
                <TableCell>{foc.reason}</TableCell>
                <TableCell>{new Date(foc.createdAt).toLocaleString()}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
        <Typography className={classes.total}>Total FOC Value: {report.totalFocValue}</Typography>
      </Box>

      <Box className={classes.section}>
        <Typography variant="h5" gutterBottom>Summary</Typography>
        <Typography className={classes.total}>Total Expense: {report.totalExpense}</Typography>
        <Typography className={classes.total}>Profit: {report.profit}</Typography>
      </Box>
    </div>
  );
}
